import{_ as t,r as l,o as a,c as o,a as e,b as r,d as n,e as c}from"./app-25fa875f.js";const d={},s=c(`<h1 id="docker-multi-stage-build" tabindex="-1"><a class="header-anchor" href="#docker-multi-stage-build" aria-hidden="true">#</a> Docker Multi-Stage Build</h1><p>Created by : Mr Dk.</p><p>2022 / 05 / 11 23:35</p><p>Hangzhou, Zhejiang, China</p><hr><p>目的：产生更小的镜像。</p><h2 id="background" tabindex="-1"><a class="header-anchor" href="#background" aria-hidden="true">#</a> Background</h2><p>最近要发布一个带有可执行文件的 Docker 镜像，可供用户直接 <code>docker run</code> 起来就可以使用了。其中，可执行文件需要通过源码编译获取。</p><p>所以最简单的做法是：</p><ol><li>在容器内准备好编译代码和运行可执行文件的所有依赖</li><li>克隆源码</li><li>编译构建可执行文件</li><li>镜像打包</li></ol><p>但是这种做法有几个问题：</p><ul><li>镜像内的编译工具在编译完毕后不再被使用</li><li>镜像内的源码没有必要保留，但是删除源码并不能减小镜像大小</li></ul><h2 id="multi-stage-image-building" tabindex="-1"><a class="header-anchor" href="#multi-stage-image-building" aria-hidden="true">#</a> Multi-Stage Image Building</h2><p>Docker 支持多阶段的镜像构建，这是减小最终镜像的有效手段。多阶段构建允许在一个 Dockerfile 中使用多个 <code>FROM</code> 指令。配合 <code>COPY --from</code> 指令将 <strong>编译镜像</strong> 中构建完毕的可执行文件拷贝到另一个 <strong>运行时镜像</strong> 当中。其中：</p><ul><li>编译镜像中包含编译源码所需要的所有依赖</li><li>运行时镜像中包含可执行文件运行所需要的所有依赖</li><li>编译镜像中产生的可执行文件被拷贝到运行时镜像中</li></ul><p>这样来看，运行时镜像的层次主要有：</p><ul><li>基础镜像</li><li><s>编译工具和依赖</s></li><li>运行时依赖</li><li><s>源码</s></li><li>可执行文件</li><li><s>（删除源码）</s></li></ul><p>可见，多阶段构建的镜像能够减少不必要的镜像层，从而减小镜像的大小。</p><h2 id="practice" tabindex="-1"><a class="header-anchor" href="#practice" aria-hidden="true">#</a> Practice</h2><p>其具体实践方式的伪代码如下：</p><div class="language-Dockerfile line-numbers-mode" data-ext="Dockerfile"><pre class="language-Dockerfile"><code>FROM building_image AS building
RUN install building tools
RUN clone the code
RUN build the code

FROM running_image
RUN install running dependencies
COPY --from=building &lt;path_in_building_image&gt; &lt;path_in_running_image&gt;
ENTRYPOINT ...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>最终，发布运行版的容器镜像即可。</p><p>其中 <code>COPY</code> 指令有一个挺坑的地方：如果想递归拷贝整个目录（保持目录和文件的结构），那么 <strong>不能使用通配符</strong>，否则目录的结构将会被 <strong>拉平</strong>。这与 <code>cp</code> 命令不同。</p><blockquote><p>It&#39;s important to note that the secret sauce here is that there is ONE source directory, and ONE target directory specified. Any other combination copies the contents of the source directory(ies) to the target directory.</p></blockquote><h2 id="references" tabindex="-1"><a class="header-anchor" href="#references" aria-hidden="true">#</a> References</h2>`,25),u={href:"https://levelup.gitconnected.com/docker-multi-stage-builds-and-copy-from-other-images-3bf1a2b095e0",target:"_blank",rel:"noopener noreferrer"},h={href:"https://stackoverflow.com/questions/30215830/dockerfile-copy-keep-subdirectory-structure",target:"_blank",rel:"noopener noreferrer"};function p(g,b){const i=l("ExternalLinkIcon");return a(),o("div",null,[s,e("p",null,[e("a",u,[r("About Docker Multi-Stage Builds and COPY --from"),n(i)])]),e("p",null,[e("a",h,[r("stackoverflow - Dockerfile copy keep subdirectory structure"),n(i)])])])}const f=t(d,[["render",p],["__file","Docker Multi-Stage Build.html.vue"]]);export{f as default};
